commands.cmd:
systemctl list-units --type=service --state=failed --no-legend --plain 2>/dev/null \
  | awk '
      {
        unit=$1
        if (unit != "") {
          gsub(/\\/, "\\\\", unit)
          gsub(/"/, "\\\"", unit)
          arr[n++]=unit
        }
      }
      END {
        printf "{\"failed\":[";
        for (i=0;i<n;i++) { printf "%s{\"unit\":\"%s\"}", (i?",":""), arr[i] }
        printf "],\"failed_names\":\"";
        for (i=0;i<n;i++) { printf "%s%s", (i?", ":""), arr[i] }
        printf "\"}";
      }'
